mapper.insert:
insert into scrim(
	scrim_id, scrim_tournament, scrim_red_team, scrim_red_score,
	scrim_blue_team, scrim_blue_score, scrim_date, scrim_created_by
) values(
 scrim_seq.nextval, #{scrimTournament}, #{scrimRedTeam},#{scrimRedScore},
 #{scrimBlueTeam},#{scrimBlueScore},#{scrimDate},#{scrimCreatedBy}
)

mapper.select:
select * from scrim_list
where scrim_tournament = #{scrimTournament}
order by scrim_date desc, scrim_id desc

select * from scrim_record
where scrim_tournament = #{scrimTournament}
order by scrim_win_count desc

select * from scrim_vs_record
where scrim_tournament = #{scrimTournament}
	and scrim_team = #{scrimTeam}
	order by vs_win_count desc
